// Product detail data interface
export interface ProductDetail {
  name: string;
  description: string;
  // Optional short marketing subtitle shown under product title
  tagline?: string;
  // Optional gallery of additional images used for the product carousel
  gallery?: string[];
  // Optional content section below hero
  sectionTitle?: string;
  body?: string[]; // paragraphs
  // SEO metadata
  metaTitle?: string; // If not provided, auto-generated
  metaDescription?: string; // If not provided, uses description
  focusKeyword?: string; // Primary SEO keyword for this product
  // Product specifications (will only display if present)
  specs?: Record<string, string>;
  species: string;
  grade: string;
  surface: string;
  width: string;
  thickness: string;
  length: string;
  finish: string;
  image: string;
  tags: string[];
}

